// Configuration
const TARGET_TIMEZONE = 'UTC'; // UTC is effectively GMT for this purpose
const HOURS_TO_LOOK_BACK = 24; // How many hours back to search

// 1. Calculate the Cutoff Time
const now = new Date();
// Subtract 24 hours (in milliseconds) from current time
const cutoffTime = new Date(now.getTime() - (HOURS_TO_LOOK_BACK * 60 * 60 * 1000));

// Helper function to get clean Time (HH:MM AM/PM)
function getGMTTime(isoDate) {
    const dateObj = new Date(isoDate);
    return dateObj.toLocaleTimeString('en-US', {
        timeZone: TARGET_TIMEZONE,
        hour: '2-digit',
        minute: '2-digit',
        hour12: true
    });
}

// Helper function to get Date (Month/Day) for display context
function getGMTDateDisplay(isoDate) {
    const dateObj = new Date(isoDate);
    return dateObj.toLocaleDateString('en-US', {
        timeZone: TARGET_TIMEZONE,
        month: 'short',
        day: 'numeric'
    });
}

// 2. Filter & Map Data
const filteredNews = $input.all()
    .map(item => item.json) // Access the JSON data
    .filter(item => {
        // Safety check if date exists
        if (!item.isoDate) return false;

        // Create a date object from the RSS item
        const itemDate = new Date(item.isoDate);

        // Compare timestamps: Keep if itemDate is NEWER (greater) than cutoffTime
        return itemDate >= cutoffTime;
    })
    .map(item => {
        // Clean up the description
        let cleanDesc = (item.contentSnippet || item.description || "")
            .replace(/\s+/g, ' ') 
            .replace(/<[^>]*>?/gm, '') // Optional: strip HTML tags if present
            .trim();

        return {
            title: item.title,
            dateRaw: item.isoDate,
            // We add the Date to the display now, since "Last 24h" spans two days
            dateDisplay: `${getGMTDateDisplay(item.isoDate)} ${getGMTTime(item.isoDate)}`, 
            description: cleanDesc
        };
    });

// 3. Construct LLM-Friendly Markdown
let markdownOutput = "";

if (filteredNews.length === 0) {
    markdownOutput = `No news found in the last ${HOURS_TO_LOOK_BACK} hours.`;
} else {
    markdownOutput = `## News Summary (Last ${HOURS_TO_LOOK_BACK} Hours)\n\n`;

    // Sort by date (Newest first)
    filteredNews.sort((a, b) => new Date(b.dateRaw) - new Date(a.dateRaw));

    filteredNews.forEach((news, index) => {
        markdownOutput += `### ${index + 1}. ${news.title}\n`;
        markdownOutput += `**Time:** ${news.dateDisplay} (${TARGET_TIMEZONE})\n`;
        markdownOutput += `**Summary:** ${news.description}\n`;
        markdownOutput += `\n---\n\n`; 
    });
}

// 4. Return Data
return [{
    json: {
        news_count: filteredNews.length,
        time_window_start: cutoffTime.toISOString(),
        markdown: markdownOutput
    }
}];

