parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "sessions": {
      "type": "array",
      "description": "A list of trading sessions",
      "items": {
        "type": "object",
        "properties": {
          "session_name": {
            "type": "string",
            "description": "Name of the session, e.g., 'Euro/London' or 'New York'"
          },
          "start_time": {
            "type": "string",
            "description": "Start time in ISO 8601/RFC 3339 format"
          },
          "end_time": {
            "type": "string",
            "description": "Step Out time in ISO 8601/RFC 3339 format"
          },
          "Reason/Summary": {
            "type": "string",
            "description": "Logic of the time selected"
          }
        },
        "required": ["session_name", "start_time", "end_time", "Reason/Summary"]
      }
    }
  },
  "required": ["sessions"]
}

